#!/usr/bin/env node
/**
 * Sync canonical skill reference content into the docs site at build time.
 *
 * Single source of truth: `skills/lich-instrument/references/*.md`.
 * The docs site copies the markdown verbatim (minus a generated-from header)
 * so any edits to the skill references automatically flow into the published
 * site on the next build.
 *
 * DO NOT edit the generated files directly — they're rewritten on every
 * `npm run docs:build` / `npm run docs:dev`. Edit the source files instead.
 */
import { copyFileSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { dirname, join, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

// docs/site/scripts/ → docs/site/ → docs/ → <repo-root>
const SITE_ROOT = resolve(__dirname, "..");
const REPO_ROOT = resolve(SITE_ROOT, "..", "..");
const REFS_DIR = join(REPO_ROOT, "skills", "lich-instrument", "references");

/**
 * Each entry copies one source into one destination, prepending a header
 * that points readers back at the canonical source.
 */
const COPIES = [
  {
    src: join(REFS_DIR, "lich-yaml-spec.md"),
    dst: join(SITE_ROOT, "reference", "lich-yaml.md"),
    relSrc: "skills/lich-instrument/references/lich-yaml-spec.md",
  },
  {
    src: join(REFS_DIR, "recipes.md"),
    dst: join(SITE_ROOT, "recipes", "index.md"),
    relSrc: "skills/lich-instrument/references/recipes.md",
  },
];

function header(relSrc) {
  return [
    "<!--",
    `  Generated from ${relSrc} — DO NOT EDIT this file directly.`,
    "  Edit the source instead; this file is rewritten on every docs build by",
    "  docs/site/scripts/sync-skill-content.mjs.",
    "-->",
    "",
  ].join("\n");
}

function syncOne({ src, dst, relSrc }) {
  const body = readFileSync(src, "utf8");
  mkdirSync(dirname(dst), { recursive: true });
  writeFileSync(dst, header(relSrc) + body, "utf8");
  console.log(`  ${relSrc}  ->  ${dst.replace(SITE_ROOT + "/", "")}`);
}

console.log("[sync-skill-content] copying canonical skill references...");
for (const entry of COPIES) {
  syncOne(entry);
}
console.log(`[sync-skill-content] done (${COPIES.length} files).`);
